function modalToggle(e,o){e.style.display=o}const btnOpenModal=document.querySelectorAll("[data-show-modal]"),modalWindow=document.querySelector("[data-modal]");for(let e of btnOpenModal)e.addEventListener("click",()=>{modalToggle(modalWindow,"block")});const crossCloseModal=document.querySelectorAll("[data-close-modal]");for(let e of crossCloseModal)e.addEventListener("click",e=>{modalToggle(e.target.closest("[data-modal]"),"none")});const reviewsSlider=new Swiper(".reviews",{navigation:{prevEl:".reviews__nav-prev",nextEl:".reviews__nav-next"},simulateTouch:!0,touchRatio:1,touchAngle:45,grabCursor:!0,loop:!0,spaceBetween:0,breakpoints:{1440:{spaceBetween:40},768:{spaceBetween:100},430:{spaceBetween:50},375:{spaceBetween:10},360:{spaceBetween:15},344:{spaceBetween:20}},autoplay:{delay:3e3}}),questions=document.querySelectorAll(".question");questions.forEach(e=>{e.addEventListener("click",()=>{const o=e.querySelector(".question__answer"),t=o.classList,a=e.querySelector(".question__cross");let l=`${o.scrollHeight}px`,s=45;t.contains("question_active")?(t.remove("question_active"),l=0,s=0):t.add("question_active"),a.style.transform=`rotate(${s}deg)`,o.style.height=l})});